<?php
require_once __DIR__.'/../includes/config.php';require_admin();
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$id=(int)($_POST['id']??0);$newStatus=(string)($_POST['status']??'');$allowed=['pending','processing','shipped','delivered','cancelled'];if(!in_array($newStatus,$allowed,true)){flash('error','Status tidak valid.');redirect('admin/orders.php');}$conn=db();$conn->begin_transaction();try{$s=$conn->prepare('SELECT status FROM orders WHERE id=? FOR UPDATE');$s->bind_param('i',$id);$s->execute();$order=$s->get_result()->fetch_assoc();$s->close();if(!$order)throw new RuntimeException('Pesanan tidak ditemukan.');$old=$order['status'];if($old==='cancelled'&&$newStatus!=='cancelled')throw new RuntimeException('Pesanan yang dibatalkan tidak dapat diaktifkan kembali.');if($old!=='cancelled'&&$newStatus==='cancelled'){$items=$conn->prepare('SELECT product_id,quantity FROM order_items WHERE order_id=? AND product_id IS NOT NULL');$items->bind_param('i',$id);$items->execute();$result=$items->get_result();$restore=$conn->prepare('UPDATE products SET stock=stock+? WHERE id=?');while($item=$result->fetch_assoc()){$qty=(int)$item['quantity'];$productId=(int)$item['product_id'];$restore->bind_param('ii',$qty,$productId);$restore->execute();}$restore->close();$items->close();}$u=$conn->prepare('UPDATE orders SET status=? WHERE id=?');$u->bind_param('si',$newStatus,$id);$u->execute();$u->close();$conn->commit();flash('success','Status pesanan berhasil diperbarui.');}catch(Throwable $e){$conn->rollback();flash('error',$e->getMessage());}redirect('admin/orders.php');}
$statusFilter=(string)($_GET['status']??'');$sql='SELECT o.*,u.name AS customer_name FROM orders o JOIN users u ON u.id=o.user_id';if(in_array($statusFilter,['pending','processing','shipped','delivered','cancelled'],true)){$sql.=' WHERE o.status=?';$stmt=db()->prepare($sql.' ORDER BY o.created_at DESC');$stmt->bind_param('s',$statusFilter);$stmt->execute();$orders=$stmt->get_result();}else{$stmt=null;$orders=db()->query($sql.' ORDER BY o.created_at DESC');}$pageTitle='Pesanan';require __DIR__.'/admin_header.php';
?>
<div class="section-head"><div><span class="eyebrow">Transaksi</span><h1>Manajemen Pesanan</h1></div></div><form class="filter-bar" method="get"><select name="status"><option value="">Semua status</option><?php foreach(['pending','processing','shipped','delivered','cancelled'] as $status): ?><option value="<?= e($status) ?>" <?= $statusFilter===$status?'selected':'' ?>><?= e(ucfirst($status)) ?></option><?php endforeach; ?></select><button class="btn btn-primary">Filter</button><a class="btn btn-outline" href="<?= e(url('admin/orders.php')) ?>">Reset</a></form><div class="panel"><div class="table-wrap"><table class="table"><thead><tr><th>Invoice</th><th>Customer</th><th>Total</th><th>Status</th><th>Ubah Status</th><th></th></tr></thead><tbody><?php while($o=$orders->fetch_assoc()): ?><tr><td><strong><?= e($o['invoice_number']) ?></strong><small><?= e(date('d-m-Y H:i',strtotime($o['created_at']))) ?></small></td><td><?= e($o['customer_name']) ?></td><td><?= rupiah($o['total_amount']) ?></td><td><span class="status status-<?= e($o['status']) ?>"><?= e(ucfirst($o['status'])) ?></span></td><td><?php if($o['status']==='cancelled'): ?><span class="muted">Final</span><?php else: ?><form method="post" class="inline-form"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)$o['id'] ?>"><select name="status"><?php foreach(['pending','processing','shipped','delivered','cancelled'] as $status): ?><option value="<?= e($status) ?>" <?= $o['status']===$status?'selected':'' ?>><?= e(ucfirst($status)) ?></option><?php endforeach; ?></select><button class="btn btn-outline btn-sm">Simpan</button></form><?php endif; ?></td><td><a href="<?= e(url('admin/order_detail.php?id='.$o['id'])) ?>">Detail</a></td></tr><?php endwhile; ?></tbody></table></div></div>
<?php if($stmt)$stmt->close();require __DIR__.'/admin_footer.php'; ?>
